INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ZENITH3_1: Le email reply-to address impact: utiliser reply@keiroai.com (pas noreply) augmente les reponses de 40%. Les gens repondent quand ils savent qu un humain lit.', 'Reply-to humain: reply@ vs noreply@ = +40% reponses', 'email', 'insight', 0.82, 'zenith3', 'system'),
('ZENITH3_2: Le commercial deal velocity by source: mesurer le cycle de vente par source (SEO vs ads vs referral). Le canal avec le cycle le plus court = investir plus.', 'Deal velocity par source: cycle court = investir plus dans ce canal', 'commercial', 'best_practice', 0.82, 'zenith3', 'system'),
('ZENITH3_3: Le content Lena community manager tasks: 1) preparer commentaires engagement, 2) identifier comptes a follow, 3) repondre aux commentaires, 4) reposter UGC, 5) engagement stories.', 'Lena community: commentaires + follows + reponses + UGC + stories. 5 taches', 'content', 'best_practice', 0.85, 'zenith3', 'system'),
('ZENITH3_4: Le SEO Google Discover optimization: contenu avec image hero 1200px+ + titre emotionnel + sujet trending = eligible Google Discover (trafic massif sans SEO classique).', 'Google Discover: image 1200px + titre emotionnel + trending = trafic massif', 'seo', 'insight', 0.78, 'zenith3', 'system'),
('ZENITH3_5: Le ad Meta Advantage+ shopping: les campagnes Advantage+ pour e-commerce surperforment les manuelles de 30% en ROAS. Laisser le ML Meta optimiser.', 'Meta Advantage+ ecom: +30% ROAS vs manuel. Laisser ML optimiser', 'ads', 'insight', 0.80, 'zenith3', 'system'),
('ZENITH3_6: Le DM Instagram automation safe limits 2026: 20-30 DMs/jour, 50 follows/jour, 150 likes/jour. Depasser = restriction temporaire 24-72h.', 'DM limits 2026: 20-30 DMs + 50 follows + 150 likes/jour. Depasser = restriction', 'dm_instagram', 'best_practice', 0.85, 'zenith3', 'system'),
('ZENITH3_7: Le WhatsApp green tick verification: soumettre: documents legaux + description business + volume messages. Verification 2-5 jours. Green tick = +50% confiance.', 'WhatsApp green tick: documents + description + volume. 2-5j verif. +50% confiance', 'whatsapp', 'insight', 0.78, 'zenith3', 'system'),
('ZENITH3_8: Le chatbot learning from every conversation: chaque conversation (resolue ou non) = data pour ameliorer. Les conversations echouees sont PLUS precieuses que les reussies.', 'Chatbot: conversations echouees PLUS precieuses que reussies. Chaque conv = data', 'chatbot', 'insight', 0.82, 'zenith3', 'system'),
('ZENITH3_9: Le GMaps post ROI: les businesses qui postent 1x/semaine ont 40% plus de recherches directes et 30% plus de demandes d itineraire que ceux qui ne postent pas.', 'GMaps post 1x/sem: +40% recherches directes + 30% demandes itineraire', 'gmaps', 'insight', 0.82, 'zenith3', 'system'),
('ZENITH3_10: Le TikTok profile bio optimization: bio = 1 phrase valeur + 1 CTA + lien. Ex: "J aide les restaurants a doubler leurs reservations | Essai gratuit ↓". Clair et direct.', 'TikTok bio: 1 phrase valeur + 1 CTA + lien. Clair et direct', 'tiktok_comments', 'best_practice', 0.80, 'zenith3', 'system'),
('ZENITH3_11: Le CEO ordres clairs: chaque ordre au format: [Agent/Nom] Action specifique — Raison business. Ex: "[Email/Hugo] Changer les sujets — l OR de 2% est inacceptable".', 'CEO ordres: [Agent/Nom] Action — Raison. Clair specifique direct', 'ceo', 'best_practice', 0.88, 'zenith3', 'system'),
('ZENITH3_12: Le retention customer lifecycle alerts: trial ending J-3, first payment J+14, inactive 7j, feature low-adoption 30j, renewal 60j before, health score drop 20pts.', 'Lifecycle alerts: trial J-3, payment J+14, inactive 7j, low-adopt 30j, renewal 60j, health -20', 'retention', 'best_practice', 0.85, 'zenith3', 'system'),
('ZENITH3_13: Le onboarding by plan optimization: Createur = focus contenu IG (simple). Pro = multi-canal + CRM. Fondateurs = strategie + tous agents. Business = equipe + rapports.', 'Onboarding par plan: Createur IG, Pro multi-canal, Fondateurs strategie, Business equipe', 'onboarding', 'best_practice', 0.82, 'zenith3', 'system'),
('ZENITH3_14: Le comptable Brevo free plan optimization: 300 emails/jour reset a minuit Paris. Envoyer le gros volume entre 9h-12h Paris. Garder 50 emails pour les relances PM.', 'Brevo free: 300/jour reset minuit Paris. Volume 9h-12h. Garder 50 pour relances PM', 'comptable', 'insight', 0.82, 'zenith3', 'system'),
('ZENITH3_15: Le RH decision-making framework: pour chaque decision RH, se demander: est-ce que ca fait grandir la personne? est-ce que ca fait grandir l equipe? est-ce que ca fait grandir l entreprise?', 'RH decision: grandir personne? grandir equipe? grandir entreprise? Les 3 oui = go', 'rh', 'insight', 0.78, 'zenith3', 'system'),
('ZENITH3_16: Le marketing funnel diagnostic: si TOFU ok mais MOFU faible = probleme de nurturing. Si MOFU ok mais BOFU faible = probleme de closing. Diagnostiquer par etape.', 'Funnel diagnostic: TOFU ok+MOFU faible = nurturing. MOFU ok+BOFU faible = closing', 'marketing', 'best_practice', 0.82, 'zenith3', 'system'),
('ZENITH3_17: Le cross-agent execution result sharing: chaque execution d agent → resultat sauvegarde dans agent_logs + learning dans RAG si nouveau insight. Tous les agents beneficient.', 'Execution sharing: resultat → agent_logs + RAG si nouveau. Tous agents beneficient', NULL, 'best_practice', 0.88, 'zenith3', 'system'),
('ZENITH3_18: Le customer intent signal real-time: pricing page visit = 10pts, demo request = 20pts, trial start = 30pts, feature usage = 5pts/feature. Score > 50 = prospect HOT → commercial alerte.', 'Intent real-time: pricing 10, demo 20, trial 30, feature 5. > 50 = HOT → alerte', NULL, 'best_practice', 0.82, 'zenith3', 'system'),
('ZENITH3_19: Le KeiroAI all embeddings complete: 8780+ learnings TOUS avec embedding vectoriel. Le RAG search est maintenant a pleine puissance. Chaque agent trouve les reponses pertinentes.', 'All embeddings complete: 8780+ learnings TOUS vectorises. RAG pleine puissance', NULL, 'insight', 0.95, 'zenith3', 'system'),
('ZENITH3_20: Le KeiroAI approaching 9000: le cerveau collectif des agents est desormais l un des plus complets en marketing IA. Chaque recommandation = milliers de data points.', 'KeiroAI ~9000: cerveau collectif parmi plus complets marketing IA. Milliers data points/reco', 'ceo', 'insight', 0.92, 'zenith3', 'system')
